import{_ as a,o as e,c as d,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Yahoo Ads","description":"","frontmatter":{"title":"Yahoo Ads","slug":"yahoo-ads"},"headers":[],"relativePath":"marketer-hub/yahoo-ads.md","filePath":"marketer-hub/yahoo-ads.md"}'),o={name:"marketer-hub/yahoo-ads.md"};function n(i,t,h,s,l,p){return e(),d("div",null,[...t[0]||(t[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><em>[Image: 220]</em></p><p>Yahoo is a global media and tech company that reaches nearly 900 million people around the world, bringing them closer to finance, sports, shopping, gaming, and news—with the trusted products, content, and tech that fuel their day. For partners, we provide a full-stack platform for businesses to amplify growth and drive more meaningful connections across advertising, search, and media. To learn more, please visit <a href="http://yahooinc.com" target="_blank" rel="noreferrer">yahooinc.com</a>.</p><h4 id="support-campaigns" tabindex="-1">Support Campaigns <a class="header-anchor" href="#support-campaigns" aria-label="Permalink to &quot;Support Campaigns&quot;">​</a></h4><ul><li>Native - Yahoo Preferred Network (YPN)</li><li>Native - Open Exchange</li><li>Display</li><li>Video</li><li>Connected TV</li><li>Audio</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>Branch connects with Yahoo for running app campaigns.</p></li><li><p>User sees an ad to download app.</p></li><li><p>User installs the app and converts.</p></li><li><p>Branch communicates with the ad network via API integration to see if they will claim attribution.</p><ul><li>If Yahoo claims attribution, they will respond back to Branch with event details.</li></ul></li><li><p>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across platforms, ad set name, ad partner, etc.</p></li></ol><h2 id="enabling-yahoo-ads" tabindex="-1">Enabling Yahoo Ads <a class="header-anchor" href="#enabling-yahoo-ads" aria-label="Permalink to &quot;Enabling Yahoo Ads&quot;">​</a></h2><h4 id="_1-navigate-to-partner-management-in-the-branch-dashboard" tabindex="-1">1. Navigate to <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management</a> in the Branch Dashboard <a class="header-anchor" href="#_1-navigate-to-partner-management-in-the-branch-dashboard" aria-label="Permalink to &quot;1. Navigate to [Partner Management](https://dashboard.branch.io/ads/partner-management) in the Branch Dashboard&quot;">​</a></h4><h4 id="_2-scroll-down-or-use-the-search-box-to-look-for-yahoo" tabindex="-1">2. Scroll down or use the search box to look for <strong>Yahoo</strong> <a class="header-anchor" href="#_2-scroll-down-or-use-the-search-box-to-look-for-yahoo" aria-label="Permalink to &quot;2. Scroll down or use the search box to look for **Yahoo**&quot;">​</a></h4><h4 id="_3-insert-your-yahoo-pixel-id-into-the-yahoo-pixel-id-field" tabindex="-1">3. Insert your <a href="https://help.yahooinc.com/dsp-api/docs/pixels" target="_blank" rel="noreferrer">Yahoo Pixel ID</a> into the <strong>Yahoo Pixel ID</strong> field. <a class="header-anchor" href="#_3-insert-your-yahoo-pixel-id-into-the-yahoo-pixel-id-field" aria-label="Permalink to &quot;3. Insert your [Yahoo Pixel ID](https://help.yahooinc.com/dsp-api/docs/pixels) into the **Yahoo Pixel ID** field.&quot;">​</a></h4><h4 id="_4-read-and-accept-the-terms-of-service" tabindex="-1">4. Read and <strong>Accept</strong> the Terms of Service. <a class="header-anchor" href="#_4-read-and-accept-the-terms-of-service" aria-label="Permalink to &quot;4. Read and **Accept** the Terms of Service.&quot;">​</a></h4><p><em>[Image: 1288]</em></p><h4 id="_5-configure-your-events-under-the-events-config-tab" tabindex="-1">5. Configure your events under the <a href="https://dashboard.branch.io/ads/partner-management/a_yahoo_san?tab=events" target="_blank" rel="noreferrer">Events Config</a> tab. <a class="header-anchor" href="#_5-configure-your-events-under-the-events-config-tab" aria-label="Permalink to &quot;5. Configure your events under the [Events Config](https://dashboard.branch.io/ads/partner-management/a_yahoo_san?tab=events) tab.&quot;">​</a></h4><p>Branch tracked events should automatically be mapped to the correct event names in Yahoo. Be sure to map custom events as well. Please follow the guide <a href="./track-branch-events.html">here</a> on tracking events with Branch.</p><h4 id="_6-save-your-settings" tabindex="-1">6. Save your settings. <a class="header-anchor" href="#_6-save-your-settings" aria-label="Permalink to &quot;6. Save your settings.&quot;">​</a></h4><p>It may take some time for Branch and Yahoo to start exchanging data. Please allow up to 48 hours for data to show in the Branch Dashboard and in Yahoo.</p><h2 id="yahoo-mappings" tabindex="-1">Yahoo Mappings <a class="header-anchor" href="#yahoo-mappings" aria-label="Permalink to &quot;Yahoo Mappings&quot;">​</a></h2><h3 id="yahoo-data-mapping" tabindex="-1">Yahoo Data Mapping <a class="header-anchor" href="#yahoo-data-mapping" aria-label="Permalink to &quot;Yahoo Data Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Yahoo Attribution Tag</th><th>Branch Analytics Tag</th><th>Example Value</th></tr></thead><tbody><tr><td>n/a</td><td>$3p</td><td>a_yahoo_san</td></tr><tr><td>n/a</td><td>~advertising_partner_name</td><td>Yahoo</td></tr><tr><td>engagement_time</td><td>last_attributed_touch_timestamp</td><td>1455675372963</td></tr><tr><td>campaign_name</td><td>~campaign</td><td>Light Bright Launch</td></tr><tr><td>campaign_id</td><td>~campaign_id</td><td>15292426</td></tr><tr><td>adgroup_name</td><td>~ad_set_name</td><td>Example name</td></tr><tr><td>adgroup_id</td><td>~ad_set_id</td><td>235465654654</td></tr><tr><td>creative_name</td><td>~ad_name &amp; ~creative_name</td><td>Creative name</td></tr><tr><td>creative_id</td><td>~ad_id &amp; ~creative_id</td><td>123456</td></tr><tr><td>demand_platform_id</td><td>~channel</td><td>1 or 2 <strong>Note</strong>: - 1: Native Ad Platform (O&amp;O) - 2: Verizon Media DSP</td></tr><tr><td>campaign_type</td><td>~tags</td><td>App Install</td></tr><tr><td>network_id</td><td>~network</td><td>456456</td></tr><tr><td>site_id</td><td>~secondary_publisher</td><td>dhjs8723tgajshd23a</td></tr><tr><td>event_type</td><td>last_attributed_touch_type</td><td>CLICK or IMPRESSION</td></tr></tbody></table><h3 id="yahoo-event-mapping" tabindex="-1">Yahoo Event Mapping <a class="header-anchor" href="#yahoo-event-mapping" aria-label="Permalink to &quot;Yahoo Event Mapping&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Branch Event</th><th>Yahoo Event</th><th>Event Category</th></tr></thead><tbody><tr><td>INSTALL</td><td>n/a - specific endpoint</td><td>n/a - specific endpoint</td></tr><tr><td>PURCHASE</td><td>Purchased</td><td>Purchase</td></tr><tr><td>INITIATE_PURCHASE</td><td>InitiatedCheckout</td><td>Initiate Checkout</td></tr><tr><td>ADD_TO_CART</td><td>AddedToCart</td><td>Add to Cart</td></tr><tr><td>VIEW_ITEM</td><td>ViewedContent</td><td>View Content</td></tr><tr><td>ADD_PAYMENT_INFO</td><td>AddedPaymentInfo</td><td>Add Payment Info</td></tr><tr><td>COMPLETE_REGISTRATION</td><td>CompletedRegistration</td><td>Others</td></tr><tr><td>SEARCH</td><td>Searched</td><td>Others</td></tr><tr><td>ACHIEVE_LEVEL</td><td>AchievedLevel</td><td>Others</td></tr><tr><td>OPEN, REINSTALL</td><td>ActivatedApp</td><td>Others</td></tr><tr><td>COMPLETE_TUTORIAL</td><td>CompletedTutorial</td><td>Others</td></tr><tr><td>ADD_TO_WISHLIST</td><td>AddedToWishlist</td><td>Add To Wishlist</td></tr><tr><td>UNLOCK_ACHIEVEMENT</td><td>UnlockedAchievement</td><td>Others</td></tr><tr><td>SHARE</td><td>n/a</td><td>Others</td></tr><tr><td>SPEND_CREDITS</td><td>SpentCredits</td><td>Others</td></tr><tr><td>RATE</td><td>Rated</td><td>Others</td></tr><tr><td>SUBSCRIBE</td><td>SignUp</td><td>Sign Up</td></tr><tr><td>CUSTOM</td><td>Lead</td><td>Others</td></tr></tbody></table>',22)])])}const u=a(o,[["render",n]]);export{m as __pageData,u as default};
